$data_j = [
    "active" => [
        ["algo" => 374, "uuid" => "dbb9c5", "name" => "dh", "type" => "kem", "status" => "active", "title" => "Diffie-Hellman", "description_md" => "Diffie-Hellman (DH) is the original key agreement protocol by Whitfield Diffie and Martin Hellman (1976). Alice and Bob agree on group parameters (prime p, generator g), exchange g^a mod p and g^b mod p, and compute the shared secret g^(ab) mod p.\n\nDH over MODP groups is used in IKEv2 (RFC 3526 2048-bit+ groups), TLS 1.2 DHE cipher suites, and SSH. MODP 2048+ is required for security. Replaced by ECDH for performance, but FFDH at 4096-bit provides quantum resistance equivalent to RSA-4096.", "mental_model" => "Original 1976 MODP key exchange -- IKEv2 FFDH, TLS DHE legacy.", "purpose" => ["key agreement", "ipsec ikev2", "tls dhe"], "good_for" => ["ikev2 group 14+ ffdh", "tls 1.2 dhe legacy", "modp 4096 quantum resistance"], "avoid_for" => ["modp < 2048 (broken)", "general use (ecdh more efficient)"], "pros" => ["1976 standard", "ffdh 4096 quantum resistance", "no ecc required"], "cons" => ["modp slow vs ecdh", "large parameters", "< 2048 broken"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Vulnerable to Shor's algorithm. FFDH 4096 ~equivalent to RSA-4096 against quantum.", "post_quantum_status" => 2, "example" => ["scenario" => "IKEv2 Diffie-Hellman Group 14 (2048-bit)", "input" => ["p" => "rfc 3526 2048-bit prime", "g" => "2", "a" => "private key"], "output" => ["shared_secret" => "g^ab mod p"]], "flow" => ["agree on (p, g)", "Alice: g^a mod p", "Bob: g^b mod p", "shared: (g^b)^a = (g^a)^b = g^ab mod p"], "related" => ["dhp", "ecdh", "kdf-ikev2"]],
        ["algo" => 375, "uuid" => "effa0d", "name" => "dhp", "type" => "kem", "status" => "active", "title" => "DH+PSK", "description_md" => "DH+PSK combines Diffie-Hellman key exchange with a Pre-Shared Key (PSK) for mutual authentication and enhanced security. The PSK is mixed into the KDF to bind the session to a shared secret.\n\nDH+PSK is used in IKEv2 PSK mode, TLS 1.3 PSK+DHE mode (0-RTT protection), and WireGuard. Provides authentication (PSK) + forward secrecy (DH). Required for TLS 1.3 0-RTT replay protection.", "mental_model" => "DH combined with PSK for authenticated forward-secure exchange -- IKEv2 PSK, TLS 1.3 PSK+DHE.", "purpose" => ["authenticated forward-secure key agreement"], "good_for" => ["ikev2 psk mode", "tls 1.3 0-rtt psk+dhe", "wireguard psk"], "avoid_for" => ["psk-only without DH (no forward secrecy)"], "pros" => ["forward secrecy + authentication", "replay protection with psk", "wireguard/tls 1.3 standard"], "cons" => ["psk management required"], "difficulty" => 2, "security" => 5, "quantum_impact" => "DH vulnerable; PSK provides some quantum resistance if key is 256+ bits.", "post_quantum_status" => 3, "example" => ["scenario" => "TLS 1.3 PSK+DHE 0-RTT", "input" => ["psk" => "pre-shared key", "ecdh_secret" => "x25519 output"], "output" => ["early_secret" => "HKDF(psk + ecdh)"]], "flow" => ["DH exchange produces g^ab", "mix PSK into KDF with HKDF", "session keys bound to both"], "related" => ["dh", "ecdh", "kdf-tls13", "hkdf"]],
        ["algo" => 376, "uuid" => "cf799b", "name" => "ecdh", "type" => "kem", "status" => "active", "title" => "ECDH", "description_md" => "ECDH (Elliptic Curve Diffie-Hellman) is the standard key agreement using elliptic curves. More efficient than MODP DH at equivalent security levels (256-bit ECC ~ 3072-bit RSA/DH).\n\nECDH over NIST P-256 is used in TLS 1.2 ECDHE, TLS 1.3, ECDH-ES (JWE), and most modern cryptographic protocols. Always apply a KDF (HKDF, X9.63 KDF) to the raw ECDH output before use. NIST P-384 for 192-bit security.", "mental_model" => "Elliptic curve DH -- standard for TLS 1.2 ECDHE, JWE, modern key exchange.", "purpose" => ["tls ecdhe", "jwe ecdh-es", "key agreement"], "good_for" => ["tls 1.2/1.3", "jwe ecdh-es", "most symmetric key exchange"], "avoid_for" => ["long-term post-quantum (use ML-KEM)"], "pros" => ["efficient", "nist p-256 universal support", "tls standard"], "cons" => ["quantum-vulnerable", "needs KDF post-processing"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Fully broken by Shor's algorithm on quantum computer.", "post_quantum_status" => 1, "example" => ["scenario" => "TLS 1.2 ECDHE P-256 key exchange", "input" => ["alice_priv" => "random scalar", "bob_pub" => "P-256 point"], "output" => ["shared_point_x" => "x coordinate of point"]], "flow" => ["agree on curve (P-256)", "Alice: a*G = A", "Bob: b*G = B", "shared: a*B = b*A = ab*G", "KDF(x-coordinate)"], "related" => ["x25519", "ecdh-kdf", "hkdf"]],
        ["algo" => 377, "uuid" => "c8082d", "name" => "x25519", "type" => "kem", "status" => "active", "title" => "X25519", "description_md" => "X25519 is the Diffie-Hellman function over Curve25519, defined in RFC 7748. Designed by Daniel J. Bernstein for high-speed, simple, and safe implementation. Uses Montgomery form for fast and constant-time scalar multiplication.\n\nX25519 is the default key exchange in TLS 1.3, Signal Protocol, WireGuard, OpenSSH, and most modern cryptographic applications. Resistant to most side-channel attacks by design. Fast on all platforms.", "mental_model" => "Curve25519 DH -- the default modern key exchange: TLS 1.3, Signal, WireGuard.", "purpose" => ["modern key agreement", "tls 1.3", "signal", "wireguard", "ssh"], "good_for" => ["tls 1.3 key exchange", "signal protocol", "wireguard", "ssh", "general key agreement"], "avoid_for" => ["post-quantum (use ML-KEM)", "contexts requiring NIST compliance (use ECDH P-256)"], "pros" => ["constant-time by design", "simple API", "no cofactor issues", "fast", "rfc 7748 standard"], "cons" => ["quantum-vulnerable", "not FIPS (use P-256 for FIPS)"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Broken by Shor's algorithm. Transition to ML-KEM.", "post_quantum_status" => 1, "example" => ["scenario" => "X25519 key exchange (TLS 1.3)", "input" => ["alice_priv" => "32 random bytes", "bob_pub" => "32-byte public key"], "output" => ["shared" => "32-byte shared secret"]], "flow" => ["alice: A = X25519(a, G_25519)", "bob: B = X25519(b, G_25519)", "shared: X25519(a, B) = X25519(b, A)"], "related" => ["x448", "ecdh", "hkdf", "kdf-tls13"]],
        ["algo" => 378, "uuid" => "94abae", "name" => "x448", "type" => "kem", "status" => "active", "title" => "X448", "description_md" => "X448 is the Diffie-Hellman function over Curve448-Goldilocks, defined in RFC 7748. Provides 224-bit security level -- higher security than X25519 at the cost of larger keys (56 bytes vs 32 bytes).\n\nX448 is supported in TLS 1.3, OpenSSH, and applications requiring higher-security Curve25519 alternative. Used when P-384 equivalent security is needed in non-NIST context.", "mental_model" => "Curve448 DH -- 224-bit security alternative to X25519 for higher security.", "purpose" => ["high-security key agreement (224-bit)"], "good_for" => ["tls 1.3 high security", "224-bit security requirement", "long-term key exchange"], "avoid_for" => ["performance-sensitive (use x25519)", "post-quantum (use ml-kem)"], "pros" => ["224-bit security", "rfc 7748 standard", "side-channel resistant"], "cons" => ["slower than x25519", "56-byte keys larger", "quantum-vulnerable"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Broken by Shor's algorithm. Higher classical security than X25519.", "post_quantum_status" => 1, "example" => ["scenario" => "TLS 1.3 X448 high-security key exchange", "input" => ["alice_priv" => "56 random bytes", "bob_pub" => "56-byte public key"], "output" => ["shared" => "56-byte shared secret"]], "flow" => ["alice: A = X448(a, G_448)", "shared: X448(a, B) = X448(b, A)"], "related" => ["x25519", "ecdh", "hkdf"]],
        ["algo" => 380, "uuid" => "8e525b", "name" => "x3dh", "type" => "kem", "status" => "active", "title" => "X3DH", "description_md" => "X3DH (Extended Triple Diffie-Hellman) is the key agreement protocol used in Signal Protocol for asynchronous end-to-end encryption. Combines multiple DH computations to provide authentication, forward secrecy, and deniability.\n\nX3DH is the initial key agreement in Signal, WhatsApp, and iMessage (some variants). Uses 4 DH computations with identity keys, signed prekeys, and one-time prekeys. Provides forward secrecy even when one party is offline.", "mental_model" => "Signal Protocol async E2EE handshake -- 4 DH computations for auth+forward-secrecy+deniability.", "purpose" => ["signal protocol e2ee async key agreement"], "good_for" => ["signal/whatsapp e2ee", "async messaging key exchange", "offline key agreement"], "avoid_for" => ["interactive protocols (use x25519 directly)"], "pros" => ["async key agreement", "forward secrecy", "deniability", "signal standard"], "cons" => ["complex 4-DH protocol", "requires prekey server"], "difficulty" => 3, "security" => 5, "quantum_impact" => "DH operations quantum-vulnerable; post-quantum Signal being developed.", "post_quantum_status" => 1, "example" => ["scenario" => "Signal initial key agreement offline", "input" => ["ik_a" => "alice identity key", "spk_b" => "bob signed prekey", "opk_b" => "bob one-time prekey"], "output" => ["shared_secret" => "hkdf(dh1||dh2||dh3||dh4)"]], "flow" => ["dh1 = DH(ik_a, spk_b)", "dh2 = DH(ek_a, ik_b)", "dh3 = DH(ek_a, spk_b)", "dh4 = DH(ek_a, opk_b)", "SK = KDF(dh1||dh2||dh3||dh4)"], "related" => ["x25519", "hkdf", "double-ratchet"]],
        ["algo" => 381, "uuid" => "4f2738", "name" => "hpke", "type" => "kem", "status" => "active", "title" => "HPKE", "description_md" => "HPKE (Hybrid Public Key Encryption) is defined in RFC 9180. Combines a KEM (key encapsulation), KDF (HKDF), and AEAD into a single composable standard for public-key encryption.\n\nHPKE is used in TLS 1.3 ECH (Encrypted Client Hello), DNS-over-HTTPS/TLS, MLS (Messaging Layer Security), and OHTTP. Supports multiple KEM modes: X25519, P-256, P-384, P-521, X448. Post-quantum KEMs will be integrated as extensions.", "mental_model" => "RFC 9180 KEM+KDF+AEAD standard -- TLS 1.3 ECH, MLS, OHTTP foundation.", "purpose" => ["hybrid public-key encryption", "tls ech", "mls", "ohttp"], "good_for" => ["tls ech", "mls messaging", "ohttp oblivious http", "public-key encryption standard"], "avoid_for" => ["interactive key agreement (use x25519+hkdf)"], "pros" => ["rfc 9180 standard", "composable kem+kdf+aead", "multiple kem modes", "tls ech/mls/ohttp"], "cons" => ["not post-quantum natively (requires pq kem extension)"], "difficulty" => 2, "security" => 5, "quantum_impact" => "KEM side vulnerable; PQ extension (ML-KEM) being standardized.", "post_quantum_status" => 3, "example" => ["scenario" => "TLS ECH with HPKE X25519-SHA256-AES128GCM", "input" => ["recipient_pub" => "server x25519 public key", "plaintext" => "TLS ClientHello"], "output" => ["enc" => "ephemeral KEM output", "ct" => "aead ciphertext"]], "flow" => ["KEM.Encap(recipient_pub) -> (shared_secret, enc)", "HKDF extract+expand with context", "AEAD.Seal(key, nonce, pt, aad) -> ct"], "related" => ["x25519", "ml-kem-768", "hkdf", "chacha20poly1305"]],
        ["algo" => 382, "uuid" => "553800", "name" => "ecies", "type" => "kem", "status" => "active", "title" => "ECIES", "description_md" => "ECIES (Elliptic Curve Integrated Encryption Scheme) is a hybrid encryption scheme combining ECDH key agreement, a KDF, a symmetric cipher, and a MAC. Defined in IEEE 1363a and ISO 18033-2.\n\nECIES is used in blockchain (Ethereum eth_ecies), DLMS/COSEM (smart meter encryption), some PKI systems, and embedded IoT. Less standard than HPKE which should be preferred for new designs.", "mental_model" => "ECDH hybrid encryption with KDF+cipher+MAC -- Ethereum, smart meters, IoT.", "purpose" => ["hybrid ecdh encryption", "ethereum e2ee", "smart meter"], "good_for" => ["ethereum eth_ecies", "dlms/cosem smart meter", "legacy ecies compat"], "avoid_for" => ["new designs (use hpke rfc 9180)"], "pros" => ["ieee 1363a standard", "ethereum/blockchain use", "hybrid encryption"], "cons" => ["non-standard variants", "hpke preferred for new designs"], "difficulty" => 2, "security" => 4, "quantum_impact" => "ECDH quantum-vulnerable; hybrid symmetric part safe.", "post_quantum_status" => 2, "example" => ["scenario" => "Ethereum ecies encrypted message", "input" => ["recipient_pub" => "secp256k1 pub key", "message" => "data bytes"], "output" => ["ct" => "ephem_pub || iv || hmac || cipher"]], "flow" => ["ephemeral ecdh: R = r*G, shared = r*PubKey", "KDF(shared) -> key_enc, key_mac", "encrypt message with key_enc", "mac over ciphertext with key_mac"], "related" => ["hpke", "ecdh", "x963-kdf"]],
        ["algo" => 383, "uuid" => "bb708c", "name" => "rsa-oaep", "type" => "kem", "status" => "active", "title" => "RSA-OAEP", "description_md" => "RSA-OAEP (Optimal Asymmetric Encryption Padding) is the secure RSA encryption scheme defined in RFC 8017 (PKCS#1 v2.2). Uses randomized padding with MGF1 (mask generation function) to provide IND-CCA2 security.\n\nRSA-OAEP is the correct RSA encryption algorithm -- RSA-PKCS1v15 encryption is insecure (PKCS#1 v1.5 padding oracle). RSA-OAEP is used in TLS 1.2 RSA key exchange (but not TLS 1.3 which dropped RSA key exchange), JWE RSA-OAEP, and PGP/GPG.", "mental_model" => "Secure RSA encryption with OAEP padding -- JWE RSA-OAEP, GPG, TLS 1.2 RSA.", "purpose" => ["rsa public-key encryption", "jwe rsa encryption", "gpg rsa"], "good_for" => ["jwe rsa-oaep", "pgp rsa key transport", "rsa-2048+ key wrapping"], "avoid_for" => ["post-quantum (use ml-kem)", "rsa < 2048-bit", "use rsa-pkcs1v15-enc (oracle attack)"], "pros" => ["rfc 8017 standard", "ind-cca2 secure", "jwe rsa standard"], "cons" => ["quantum-vulnerable (shor)", "slower than ecies/x25519", "rsa key management"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Fully broken by Shor's algorithm. Transition to ML-KEM.", "post_quantum_status" => 1, "example" => ["scenario" => "JWE RSA-OAEP-256 key wrapping", "input" => ["rsa_pub" => "2048-bit RSA public key", "plaintext_key" => "32-byte AES-256 key"], "output" => ["encrypted_key" => "256-byte RSA-OAEP ciphertext"]], "flow" => ["OAEP: encode message with random seed + MGF1 mask", "RSA encrypt: c = m^e mod n", "decrypt: m^ed = m mod n, decode OAEP"], "related" => ["ml-kem-768", "hpke", "rsa-pkcs1v15-enc"]],
        ["algo" => 386, "uuid" => "33ece4", "name" => "csidh", "type" => "kem", "status" => "active", "title" => "CSIDH", "description_md" => "CSIDH (Commutative Supersingular Isogeny DH) is an isogeny-based post-quantum key agreement by Castryck, Lange, Martindale, Panny, and Renes (2018). Based on the commutative group action of ideal class groups on supersingular elliptic curves over Fp.\n\nCSIDH provides very compact keys (~64 bytes at CSIDH-512 security) and has non-interactive key exchange property. Slower than ECDH but post-quantum. Potential timing-channel issues in naive implementations.", "mental_model" => "Isogeny commutative group action PQ key exchange -- compact keys but slow.", "purpose" => ["post-quantum key agreement (isogeny)"], "good_for" => ["non-interactive pq key exchange", "compact pq keys"], "avoid_for" => ["production (use ml-kem)", "timing-sensitive (csidh timing leaks)"], "pros" => ["post-quantum", "non-interactive", "compact 64-byte keys", "no reconciliation"], "cons" => ["slow (10000x slower than x25519)", "timing-channel issues", "conservative security analysis"], "difficulty" => 5, "security" => 4, "quantum_impact" => "Post-quantum; based on supersingular isogeny DLP.", "post_quantum_status" => 5, "example" => ["scenario" => "CSIDH-512 post-quantum key exchange", "input" => ["alice_priv" => "secret class group element", "bob_pub" => "64-byte supersingular curve"], "output" => ["shared" => "isogeny shared point"]], "flow" => ["represent keys as class group elements", "apply isogeny walk to base curve", "Alice: a acts on Bob's pub key", "Bob: b acts on Alice's pub key", "commutativity: a(b(E)) = b(a(E))"], "related" => ["ml-kem-512", "sidh", "x25519"]],
        ["algo" => 388, "uuid" => "2fcd5a", "name" => "frodokem", "type" => "kem", "status" => "active", "title" => "FrodoKEM", "description_md" => "FrodoKEM is a conservative post-quantum KEM based on plain Learning With Errors (LWE), without ring or module structure. NIST PQC Round 3 alternate candidate.\n\nFrodoKEM uses random matrices (no algebraic structure) providing conservative security that doesn't rely on hardness of structured lattice problems. Larger keys than ML-KEM but broader security assumptions. FrodoKEM-1344 provides AES-256 equivalent security.", "mental_model" => "Conservative plain LWE KEM -- no ring structure, larger keys but broadest security assumptions.", "purpose" => ["conservative pq kem (no ring structure)"], "good_for" => ["highest-assurance pq key exchange", "frodokem-976/1344 top security"], "avoid_for" => ["size-constrained (use ml-kem)", "default pq kem (use ml-kem)"], "pros" => ["conservative plain lwe", "no algebraic structure attacks", "nist alternate candidate"], "cons" => ["large keys (>10KB)", "slower than ml-kem", "not nist primary standard"], "difficulty" => 4, "security" => 5, "quantum_impact" => "Post-quantum conservative LWE.", "post_quantum_status" => 5, "example" => ["scenario" => "FrodoKEM-976 high-security key exchange", "input" => ["bob_pub" => "15632-byte public key"], "output" => ["shared_secret" => "32 bytes", "ciphertext" => "15744 bytes"]], "flow" => ["keygen: random matrix A, secret S, E; pk = (A, AS+E)", "encap: pick r, c1=rA+e1, c2=rPK+e2+encode(m)", "decap: decode(c2 - Sc1)"], "related" => ["ml-kem-768", "kyber", "hpke"]],
        ["algo" => 389, "uuid" => "971c46", "name" => "kyber", "type" => "kem", "status" => "active", "title" => "Kyber (CRYSTALS)", "description_md" => "Kyber is the original name for the CRYSTALS-Kyber KEM before NIST standardization as ML-KEM (FIPS 203). NIST selected Kyber-768 (ML-KEM-768) as the primary PQC KEM standard in 2024.\n\nKyber/ML-KEM is based on Module-LWE. Kyber-512 ~ AES-128, Kyber-768 ~ AES-192, Kyber-1024 ~ AES-256. This entry covers the original pre-standardization 'Kyber' name for legacy references.", "mental_model" => "CRYSTALS-Kyber -- the original name for ML-KEM before FIPS 203 standardization.", "purpose" => ["pq kem (legacy kyber name)"], "good_for" => ["referring to kyber before ml-kem name transition"], "avoid_for" => ["new code: use ml-kem-768 (fips 203)"], "pros" => ["nist selected", "module-lwe basis", "well-studied"], "cons" => ["use ml-kem-* names in new code"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Post-quantum; NIST FIPS 203 standard.", "post_quantum_status" => 5, "example" => ["scenario" => "Kyber-768 (ML-KEM-768) reference", "input" => ["pk" => "1184-byte public key"], "output" => ["ct" => "1088 bytes", "ss" => "32 bytes"]], "flow" => ["same as ml-kem-768"], "related" => ["ml-kem-768", "ml-kem-512", "ml-kem-1024"]],
        ["algo" => 390, "uuid" => "200c5f", "name" => "ml-kem-512", "type" => "kem", "status" => "active", "title" => "ML-KEM-512", "description_md" => "ML-KEM-512 is the 128-bit post-quantum security level KEM standardized in NIST FIPS 203 (2024). Based on Module-LWE (CRYSTALS-Kyber-512 submission).\n\nML-KEM-512: public key 800 bytes, ciphertext 768 bytes, shared secret 32 bytes. Equivalent to AES-128 security. Fastest of the ML-KEM variants. Use when performance is critical and 128-bit PQ security is sufficient.", "mental_model" => "ML-KEM level 1 -- 128-bit PQ security, smallest/fastest ML-KEM variant (FIPS 203).", "purpose" => ["128-bit pq kem"], "good_for" => ["iot/constrained pq kem", "128-bit pq requirement"], "avoid_for" => ["high-security (use ml-kem-768 or 1024)"], "pros" => ["fips 203 standard", "smallest ml-kem keys", "fastest", "128-bit pq"], "cons" => ["128-bit only", "ml-kem-768 recommended for general use"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Post-quantum AES-128 equivalent.", "post_quantum_status" => 5, "example" => ["scenario" => "Constrained device PQ key exchange", "input" => ["pk" => "800-byte public key"], "output" => ["ct" => "768 bytes", "ss" => "32 bytes"]], "flow" => ["module-lwe keygen", "encap: sample random, compress, encode", "decap: decompress, decode"], "related" => ["ml-kem-768", "ml-kem-1024", "kyber"]],
        ["algo" => 391, "uuid" => "f0d892", "name" => "ml-kem-768", "type" => "kem", "status" => "active", "title" => "ML-KEM-768", "description_md" => "ML-KEM-768 is the 192-bit post-quantum security level KEM standardized in NIST FIPS 203 (2024). This is the recommended general-purpose ML-KEM variant (equivalent to Kyber-768).\n\nML-KEM-768: public key 1184 bytes, ciphertext 1088 bytes, shared secret 32 bytes. Recommended by NIST for most applications. Used in TLS 1.3 hybrid PQ key exchange (X25519+ML-KEM-768), Chrome/Firefox post-quantum TLS, HPKE PQ extensions.", "mental_model" => "ML-KEM recommended level -- 192-bit PQ, general-purpose TLS/HPKE KEM (FIPS 203).", "purpose" => ["recommended pq kem", "tls 1.3 pq key exchange"], "good_for" => ["tls 1.3 x25519+ml-kem-768 hybrid", "hpke pq", "most pq kem applications"], "avoid_for" => ["constrained iot (ml-kem-512)", "highest security (ml-kem-1024)"], "pros" => ["nist fips 203 recommended", "192-bit pq security", "tls 1.3 hybrid standard", "chrome/firefox pq tls"], "cons" => ["larger than classical x25519 (1184 vs 32 byte pk)"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Post-quantum AES-192 equivalent.", "post_quantum_status" => 5, "example" => ["scenario" => "TLS 1.3 X25519+ML-KEM-768 hybrid key exchange", "input" => ["pk" => "1184-byte ML-KEM-768 public key"], "output" => ["ct" => "1088 bytes", "ss" => "32 bytes", "x25519_ss" => "32 bytes", "combined" => "hkdf(x25519_ss || ml_kem_ss)"]], "flow" => ["ML-KEM encap: sample r, compress, encode ciphertext", "combine with X25519 shared secret via HKDF"], "related" => ["ml-kem-512", "ml-kem-1024", "x25519", "hpke"]],
        ["algo" => 392, "uuid" => "e0c923", "name" => "ml-kem-1024", "type" => "kem", "status" => "active", "title" => "ML-KEM-1024", "description_md" => "ML-KEM-1024 is the 256-bit post-quantum security level KEM standardized in NIST FIPS 203 (2024). Highest security ML-KEM variant (equivalent to Kyber-1024).\n\nML-KEM-1024: public key 1568 bytes, ciphertext 1568 bytes, shared secret 32 bytes. AES-256 equivalent PQ security. Use for long-term key agreement where 256-bit PQ security is required (TOP SECRET/government).", "mental_model" => "ML-KEM level 5 -- 256-bit PQ, highest security ML-KEM for government/TOP SECRET (FIPS 203).", "purpose" => ["256-bit pq kem high security"], "good_for" => ["government top secret pq kem", "256-bit long-term pq security"], "avoid_for" => ["general use (ml-kem-768 recommended)"], "pros" => ["fips 203 standard", "256-bit pq security", "aes-256 equivalent"], "cons" => ["largest ml-kem keys", "ml-kem-768 sufficient for most"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Post-quantum AES-256 equivalent.", "post_quantum_status" => 5, "example" => ["scenario" => "Government TOP SECRET PQ key exchange", "input" => ["pk" => "1568-byte public key"], "output" => ["ct" => "1568 bytes", "ss" => "32 bytes"]], "flow" => ["same as ml-kem-768 at larger module dimension"], "related" => ["ml-kem-768", "ml-kem-512", "frodokem"]],
        ["algo" => 393, "uuid" => "f4cae8", "name" => "ntru", "type" => "kem", "status" => "active", "title" => "NTRU", "description_md" => "NTRU is the original lattice-based public-key cryptosystem by Hoffstein, Pipher, and Silverman (1996). Based on polynomial rings in Z[x]/(x^N-1). One of the oldest post-quantum public-key algorithms.\n\nNTRU was a NIST PQC Round 3 finalist. Variants: NTRUhps (NTRU encryption), NTRUhrss (NTRU signature schemes). Has a 30-year cryptanalysis history. Conservative security due to long study. IEEE 1363.1 standard.", "mental_model" => "Original 1996 lattice polynomial ring PQ crypto -- 30-year history, NIST PQC finalist.", "purpose" => ["post-quantum kem (ntru lattice)"], "good_for" => ["conservative pq kem with long history", "ntru nist finalist"], "avoid_for" => ["default pq kem (use ml-kem)", "sntrup761 preferred for most ntru cases"], "pros" => ["30-year history", "no structured lattice attacks", "ieee 1363.1 standard"], "cons" => ["larger params than ml-kem", "decryption failure risk", "patent history (now expired)"], "difficulty" => 4, "security" => 5, "quantum_impact" => "Post-quantum lattice-based.", "post_quantum_status" => 5, "example" => ["scenario" => "NTRU-HPS-4096-821 key exchange", "input" => ["pk" => "1230-byte public key"], "output" => ["ct" => "1230 bytes", "ss" => "32 bytes"]], "flow" => ["keygen: f, g polynomials in R", "encrypt: e = r*h + m mod q", "decrypt: a = f*e mod q, m = a mod p"], "related" => ["sntrup761", "ml-kem-768", "ntruprime"]],
        ["algo" => 394, "uuid" => "e16761", "name" => "ntruprime", "type" => "kem", "status" => "active", "title" => "NTRU Prime", "description_md" => "NTRU Prime is a variant of NTRU by Daniel J. Bernstein (2016) using irreducible polynomial rings x^p - x - 1 over Fp to eliminate ring structure that might enable attacks.\n\nNTRU Prime addresses concerns about the ring structure of classical NTRU. Two variants: Streamlined NTRU Prime (sntrup) and NTRU LPRime (ntrulpr). sntrup761 used in OpenSSH.", "mental_model" => "Bernstein's NTRU Prime -- irreducible poly ring eliminates structure attacks, OpenSSH pq kem.", "purpose" => ["ntru variant eliminating ring structure attacks"], "good_for" => ["openssh pq kem", "conservative ntru-based pq"], "avoid_for" => ["general pq (use ml-kem)"], "pros" => ["eliminates ring structure concerns", "openssh sntrup761 standard", "djb designed"], "cons" => ["larger than ml-kem", "niche adoption"], "difficulty" => 4, "security" => 5, "quantum_impact" => "Post-quantum; conservative ring security.", "post_quantum_status" => 5, "example" => ["scenario" => "NTRU Prime key exchange", "input" => ["pk" => "1158-byte public key (sntrup761)"], "output" => ["ct" => "1039 bytes", "ss" => "32 bytes"]], "flow" => ["keys in Z[x]/(x^p-x-1)", "eliminate top-level ring attacks", "encap/decap via polynomial ops"], "related" => ["sntrup761", "ntru", "ml-kem-768"]],
    ],
    "legacy" => [
        ["algo" => 379, "uuid" => "e923a3", "name" => "ecmqv", "type" => "kem", "status" => "legacy", "title" => "ECMQV", "description_md" => "ECMQV (Elliptic Curve Menezes-Qu-Vanstone) is an authenticated elliptic curve key agreement protocol. Provides implicit key authentication without separate signature step.\n\nECMQV was included in NSA Suite B (before removal in 2015). Used in some legacy government and military systems. Concerns about potential NSA backdoor influence led to its removal from Suite B. Superseded by ECDH+signature authentication.", "mental_model" => "NSA Suite B authenticated ECDH -- removed from Suite B 2015, implicit auth KA.", "purpose" => ["legacy authenticated key agreement"], "good_for" => ["legacy suite b government systems"], "avoid_for" => ["new designs (ecdh + signature preferred)", "nsa backdoor concerns"], "pros" => ["implicit auth without extra signature", "compact protocol"], "cons" => ["removed from nsa suite b 2015", "backdoor concerns", "deprecated"], "difficulty" => 3, "security" => 3, "quantum_impact" => "Quantum-vulnerable like ECDH.", "post_quantum_status" => 1, "example" => ["scenario" => "Legacy ECMQV key agreement", "input" => ["alice_static" => "static ec key", "alice_ephemeral" => "ephemeral ec key", "bob_keys" => "static + ephemeral"], "output" => ["shared_secret" => "authenticated shared point"]], "flow" => ["combine static and ephemeral EC keys", "implicit authentication in computation"], "related" => ["ecdh", "x25519"]],
        ["algo" => 384, "uuid" => "04648c", "name" => "rsa-pkcs1v15-enc", "type" => "kem", "status" => "legacy", "title" => "RSA-PKCS#1v1.5 Enc", "description_md" => "RSA-PKCS#1v1.5 encryption is the original RSA encryption padding scheme from PKCS#1 v1.5. Vulnerable to Bleichenbacher's 1998 padding oracle attack (ROBOT attack) enabling ciphertext decryption without the private key.\n\nRSA-PKCS#1v1.5 encryption was used in TLS 1.0-1.2 RSA key exchange (not TLS 1.3). ROBOT vulnerability (CVE-2017-17382) affected billions of TLS connections. Must be replaced with RSA-OAEP or ML-KEM. TLS 1.3 dropped RSA key exchange entirely.", "mental_model" => "RSA PKCS#1 v1.5 encryption -- ROBOT padding oracle attack, never use for new code.", "purpose" => ["legacy tls 1.2 rsa key exchange (broken)"], "good_for" => ["understanding robot attack history"], "avoid_for" => ["any use (robot attack -- use rsa-oaep or ml-kem)"], "pros" => ["legacy tls 1.2 compatibility"], "cons" => ["robot attack (bleichenbacher 1998)", "cve-2017-17382", "do not use"], "difficulty" => 2, "security" => 1, "quantum_impact" => "Classically broken by padding oracle; quantum also breaks RSA.", "post_quantum_status" => 1, "example" => ["scenario" => "TLS 1.2 RSA key exchange (ROBOT-vulnerable)", "input" => ["rsa_pub" => "server 2048-bit RSA key", "premaster_secret" => "48 bytes"], "output" => ["encrypted_pms" => "rsa encrypted premaster (vulnerable)"]], "flow" => ["PKCS1v15 pad: 0x00 0x02 || random bytes || 0x00 || message", "RSA encrypt: c = m^e mod n", "ROBOT: adaptively query decryption oracle"], "related" => ["rsa-oaep", "ml-kem-768"]],
        ["algo" => 385, "uuid" => "a7a8b3", "name" => "elgamal", "type" => "kem", "status" => "legacy", "title" => "ElGamal Encryption", "description_md" => "ElGamal encryption is a public-key encryption scheme based on the discrete logarithm problem (DLP) by Taher Elgamal (1985). The receiver publishes y = g^x mod p; sender picks random k, sends (g^k mod p, m * y^k mod p).\n\nElGamal is the basis of GPG/PGP ElGamal keys and DSA. Probabilistic and IND-CPA secure in random oracle model. Superseded by RSA-OAEP and ECIES for practical use. Quantum-vulnerable via Shor's algorithm.", "mental_model" => "1985 DLP-based public key encryption -- GPG ElGamal keys, basis of DSA.", "purpose" => ["legacy gpg elgamal encryption"], "good_for" => ["gpg elgamal legacy compatibility"], "avoid_for" => ["new designs (rsa-oaep, ml-kem)", "quantum (shor breaks dlp)"], "pros" => ["gpg elgamal standard", "probabilistic encryption", "dlp basis for dsa"], "cons" => ["quantum-vulnerable", "2x ciphertext expansion", "superseded"], "difficulty" => 3, "security" => 3, "quantum_impact" => "Fully broken by Shor's algorithm (DLP).", "post_quantum_status" => 1, "example" => ["scenario" => "GPG ElGamal key decryption", "input" => ["y" => "g^x mod p public key", "m" => "plaintext"], "output" => ["ct" => "(g^k, m*y^k mod p)"]], "flow" => ["pick random k", "c1 = g^k mod p", "c2 = m * y^k mod p", "decrypt: m = c2 * (c1^x)^-1 mod p"], "related" => ["rsa-oaep", "dh", "dsa"]],
        ["algo" => 387, "uuid" => "44be13", "name" => "sike", "type" => "kem", "status" => "legacy", "title" => "SIKE (BROKEN)", "description_md" => "SIKE (Supersingular Isogeny Key Encapsulation) was a NIST PQC Round 4 candidate based on supersingular isogeny graphs. COMPLETELY BROKEN in July 2022 by Castryck and Decru's classical attack using only a laptop.\n\nSIKE was completely broken by a classical (non-quantum) attack in 2022 (Castryck-Decru). The attack exploits the auxiliary torsion point information in SIKE's construction. All SIKE parameters are broken. Never use. Historical/research interest only.", "mental_model" => "SIKE -- NIST Round 4 PQC candidate COMPLETELY BROKEN classically in 2022 (Castryck-Decru).", "purpose" => ["historical: broken pq kem"], "good_for" => ["understanding pqc attack history"], "avoid_for" => ["any use (completely broken)"], "pros" => ["historically interesting", "smallest pqc key sizes (now moot)"], "cons" => ["completely broken by classical attack (2022)", "do not use under any circumstances"], "difficulty" => 5, "security" => 1, "quantum_impact" => "Broken classically, not even quantum needed.", "post_quantum_status" => 1, "example" => ["scenario" => "SIKE - do not use (broken 2022)", "input" => [], "output" => ["warning" => "COMPLETELY BROKEN - Castryck-Decru 2022"]], "flow" => ["BROKEN: attack recovers secret key via auxiliary torsion points"], "related" => ["csidh", "ml-kem-768"]],
    ],
    "new" => [
        ["algo" => 395, "uuid" => "7f87c3", "name" => "sntrup761", "type" => "kem", "status" => "new", "title" => "sntrup761", "description_md" => "sntrup761 (Streamlined NTRU Prime 761) is the variant of NTRU Prime used in OpenSSH 8.5+ as the default post-quantum KEM. The '761' refers to the prime p=761 defining the ring Z[x]/(x^761-x-1).\n\nOpenSSH uses sntrup761x25519-sha512 hybrid key exchange (sntrup761 + X25519) since OpenSSH 8.5. Provides post-quantum protection for SSH key exchange without breaking classical security.", "mental_model" => "OpenSSH default PQ KEM -- sntrup761+X25519 hybrid, deployed in OpenSSH 8.5+.", "purpose" => ["openssh pq kem"], "good_for" => ["openssh pq hybrid key exchange"], "avoid_for" => ["general pq (use ml-kem-768)"], "pros" => ["openssh 8.5+ default", "djb designed", "761-prime ring security"], "cons" => ["larger than ml-kem", "niche non-standard use outside openssh"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Post-quantum; hybrid with X25519.", "post_quantum_status" => 5, "example" => ["scenario" => "OpenSSH 8.5+ sntrup761x25519-sha512", "input" => ["sntrup_pk" => "1158-byte pub", "x25519_pk" => "32-byte pub"], "output" => ["ct" => "sntrup1039 + x25519", "ss" => "combined shared secret"]], "flow" => ["encap sntrup761", "X25519 exchange", "combine: SHA-512(sntrup_ss || x25519_ss)"], "related" => ["ntruprime", "ntru", "x25519", "ml-kem-768"]],
        ["algo" => 396, "uuid" => "cb44d9", "name" => "classic-mceliece", "type" => "kem", "status" => "new", "title" => "Classic McEliece", "description_md" => "Classic McEliece is a code-based post-quantum KEM based on the McEliece cryptosystem (1978). Uses Goppa codes as the hard problem. NIST PQC Round 4 alternate candidate.\n\nClassic McEliece has the largest post-quantum security history (45 years of cryptanalysis). Massive public keys (1+ MB) but tiny ciphertexts (128 bytes). Goppa codes are believed harder than LWE against quantum attacks. Suitable for long-term archival or hardware security modules where key size is not constrained.", "mental_model" => "Code-based 1978 Goppa code PQ KEM -- 45-year history, huge keys (1MB), tiny ciphertext.", "purpose" => ["highest-assurance code-based pq kem"], "good_for" => ["long-term archival pq", "hsm embedded keys", "conservative code-based pq"], "avoid_for" => ["network protocols (huge pk)", "constrained devices (ml-kem)"], "pros" => ["45 years cryptanalysis", "code-based different assumption than lwe", "tiny ciphertext 128 bytes"], "cons" => ["1+ MB public key", "keygen slow", "impractical for most protocols"], "difficulty" => 5, "security" => 5, "quantum_impact" => "Post-quantum; code-based Goppa hardness.", "post_quantum_status" => 5, "example" => ["scenario" => "Classic McEliece-3488064 key exchange", "input" => ["pk" => "261120-byte public key"], "output" => ["ct" => "128 bytes", "ss" => "32 bytes"]], "flow" => ["Goppa code key generation", "message encoded as error vector", "decap: error correction decoding"], "related" => ["mceliece-348864", "ml-kem-768", "frodokem"]],
        ["algo" => 397, "uuid" => "beb9c7", "name" => "mceliece-348864", "type" => "kem", "status" => "new", "title" => "McEliece-348864", "description_md" => "McEliece-348864 is Classic McEliece parameter set for 128-bit post-quantum security. Parameters: n=3488, k=2720, t=64 (Goppa). Public key 261120 bytes.\n\nSmallest Classic McEliece parameter set. Used in research and specialized applications requiring code-based security at 128-bit PQ level.", "mental_model" => "Classic McEliece level 1 (128-bit PQ) -- smallest code-based KEM at 261KB public key.", "purpose" => ["128-bit code-based pq kem"], "good_for" => ["research, smallest mceliece"], "avoid_for" => ["practical protocols (261KB pk)"], "pros" => ["code-based pq", "128-bit pq security"], "cons" => ["261120-byte public key"], "difficulty" => 5, "security" => 4, "quantum_impact" => "Post-quantum code-based.", "post_quantum_status" => 5, "example" => ["scenario" => "McEliece-348864 encap", "input" => ["pk" => "261120 bytes"], "output" => ["ct" => "128 bytes", "ss" => "32 bytes"]], "flow" => ["goppa code encap"], "related" => ["classic-mceliece", "mceliece-6688128"]],
        ["algo" => 398, "uuid" => "c4e87e", "name" => "mceliece-348864f", "type" => "kem", "status" => "new", "title" => "McEliece-348864f", "description_md" => "McEliece-348864f is the 'fast' variant of McEliece-348864 using quasi-cyclic structure to reduce key generation time while maintaining the same security level.\n\nThe 'f' variants use a different key generation algorithm for faster keygen. Same security level and parameters as non-f variants.", "mental_model" => "McEliece-348864 fast keygen variant -- same security, faster key generation.", "purpose" => ["128-bit code-based pq kem (fast keygen)"], "good_for" => ["mceliece-348864 with faster keygen"], "avoid_for" => ["practical protocols (261KB pk)"], "pros" => ["faster keygen than non-f", "code-based pq"], "cons" => ["261120-byte pk", "fast variant different keygen path"], "difficulty" => 5, "security" => 4, "quantum_impact" => "Post-quantum code-based.", "post_quantum_status" => 5, "example" => ["scenario" => "McEliece-348864f fast keygen", "input" => ["seed" => "entropy for fast keygen"], "output" => ["pk" => "261120 bytes"]], "flow" => ["quasi-cyclic fast key generation", "same encap/decap as 348864"], "related" => ["mceliece-348864", "classic-mceliece"]],
        ["algo" => 399, "uuid" => "452b30", "name" => "mceliece-460896", "type" => "kem", "status" => "new", "title" => "McEliece-460896", "description_md" => "McEliece-460896 is Classic McEliece at 192-bit post-quantum security. Parameters: n=4608, k=3360, t=96. Public key 524160 bytes (512KB).\n\n192-bit PQ security code-based KEM. Larger than 348864 but higher security margin.", "mental_model" => "Classic McEliece level 3 (192-bit PQ) -- 512KB public key.", "purpose" => ["192-bit code-based pq kem"], "good_for" => ["192-bit pq mceliece research"], "avoid_for" => ["practical (512KB pk)"], "pros" => ["192-bit code-based pq"], "cons" => ["524160-byte pk"], "difficulty" => 5, "security" => 5, "quantum_impact" => "Post-quantum code-based.", "post_quantum_status" => 5, "example" => ["scenario" => "McEliece-460896 key exchange", "input" => ["pk" => "524160 bytes"], "output" => ["ct" => "188 bytes", "ss" => "32 bytes"]], "flow" => ["goppa code ops at 460896 params"], "related" => ["classic-mceliece", "mceliece-6688128"]],
        ["algo" => 400, "uuid" => "a5357a", "name" => "mceliece-460896f", "type" => "kem", "status" => "new", "title" => "McEliece-460896f", "description_md" => "McEliece-460896f is the fast key generation variant of McEliece-460896. Same 192-bit PQ security with faster keygen.", "mental_model" => "McEliece-460896 fast keygen variant.", "purpose" => ["192-bit code-based pq fast keygen"], "good_for" => ["mceliece-460896 faster keygen"], "avoid_for" => ["practical (512KB pk)"], "pros" => ["192-bit code-based pq", "fast keygen"], "cons" => ["524160-byte pk"], "difficulty" => 5, "security" => 5, "quantum_impact" => "Post-quantum code-based.", "post_quantum_status" => 5, "example" => ["scenario" => "McEliece-460896f", "input" => ["seed" => "entropy"], "output" => ["pk" => "524160 bytes"]], "flow" => ["fast keygen + 460896 params"], "related" => ["mceliece-460896", "classic-mceliece"]],
        ["algo" => 401, "uuid" => "dc1d1d", "name" => "mceliece-6688128", "type" => "kem", "status" => "new", "title" => "McEliece-6688128", "description_md" => "McEliece-6688128 is Classic McEliece at 256-bit post-quantum security. Parameters: n=6688, k=5024, t=128. Public key 1044992 bytes (~1MB).\n\nHighest security McEliece variant in practical use. ~1MB public key makes it impractical for most protocols but suitable for HSM or archival use.", "mental_model" => "Classic McEliece level 5 (256-bit PQ) -- ~1MB public key, highest security code-based.", "purpose" => ["256-bit code-based pq kem"], "good_for" => ["hsm archival pq", "256-bit code-based pq"], "avoid_for" => ["network protocols (1MB pk)"], "pros" => ["256-bit code-based pq", "highest code-based security"], "cons" => ["1044992-byte pk"], "difficulty" => 5, "security" => 5, "quantum_impact" => "Post-quantum AES-256 equivalent code-based.", "post_quantum_status" => 5, "example" => ["scenario" => "McEliece-6688128 key exchange", "input" => ["pk" => "1044992 bytes"], "output" => ["ct" => "240 bytes", "ss" => "32 bytes"]], "flow" => ["goppa code 6688128 params"], "related" => ["classic-mceliece", "mceliece-348864"]],
        ["algo" => 402, "uuid" => "d7a805", "name" => "mceliece-6688128f", "type" => "kem", "status" => "new", "title" => "McEliece-6688128f", "description_md" => "McEliece-6688128f is the fast keygen variant of McEliece-6688128.", "mental_model" => "McEliece-6688128 fast keygen.", "purpose" => ["256-bit code-based pq fast keygen"], "good_for" => ["mceliece-6688128 faster keygen"], "avoid_for" => ["practical protocols (1MB pk)"], "pros" => ["256-bit code-based pq", "fast keygen"], "cons" => ["~1MB pk"], "difficulty" => 5, "security" => 5, "quantum_impact" => "Post-quantum.", "post_quantum_status" => 5, "example" => ["scenario" => "McEliece-6688128f", "input" => ["seed" => "entropy"], "output" => ["pk" => "1044992 bytes"]], "flow" => ["fast keygen + 6688128 params"], "related" => ["mceliece-6688128", "classic-mceliece"]],
        ["algo" => 403, "uuid" => "ce4bce", "name" => "mceliece-6960119", "type" => "kem", "status" => "new", "title" => "McEliece-6960119", "description_md" => "McEliece-6960119 is Classic McEliece at 256-bit post-quantum security with different Goppa code parameters (n=6960, k=5413, t=119). Alternative 256-bit McEliece parametrization.", "mental_model" => "Alternative 256-bit McEliece params -- slightly different Goppa code structure.", "purpose" => ["256-bit code-based pq alternate params"], "good_for" => ["alternative mceliece 256-bit"], "avoid_for" => ["practical protocols (large pk)"], "pros" => ["256-bit alternative parametrization"], "cons" => ["~1MB pk", "prefer 6688128 for standard"], "difficulty" => 5, "security" => 5, "quantum_impact" => "Post-quantum.", "post_quantum_status" => 5, "example" => ["scenario" => "McEliece-6960119 encap", "input" => ["pk" => "1047319 bytes"], "output" => ["ct" => "226 bytes", "ss" => "32 bytes"]], "flow" => ["6960119 goppa params"], "related" => ["mceliece-6688128", "classic-mceliece"]],
